sql:
SELECT * 
FROM facility_reports
WHERE report_type = 'Bed Availability';

SELECT facility_name, total_beds
FROM facilities
ORDER BY total_beds DESC;

SELECT patient_id, facility_id
FROM patient_admissions
WHERE admission_date >= date('now', '-30 days');

SELECT staff_name
FROM facility_staff
WHERE role = 'Doctor' AND department = 'Emergency';

SELECT facility_name, total_beds
FROM facilities
WHERE total_beds > 500;

SELECT COUNT(*)
FROM patient_admissions
WHERE discharge_date IS NOT NULL;

SELECT COUNT(*) 
FROM facility_staff 
WHERE role = 'Nurse' AND department = 'ICU';

external_knowledge:
Total beds capacity = Available beds + Patient count;
Average patient count per bed = Total beds capacity / Total number of records;
"Facilities" refer to healthcare institutions like hospitals or clinics;
"Beds" are the sleeping accommodations for patients;
"Patient count" represents the number of admitted patients for a specific bed type in a facility.

